Javascript.initialise:
var parties = Services.getNodes("/ds/ManageCase/Parties/LitigiousParty");
if(Services.exists(REF_DATA_XPATH + "/Parties"))
{
	Services.removeNode(REF_DATA_XPATH +  "/Parties" );
	for(var i = 0; i < parties.length; i++) 
	{
		var party = parties[i];
		Services.addNode(party, REF_DATA_XPATH + "/Parties");	
	}
}
else
{
	for(var i = 0; i < parties.length; i++) 
	{
		var party = parties[i];
		Services.addNode(party, REF_DATA_XPATH + "/Parties");	
	}
}
